INSERT OR IGNORE INTO notices (notice_id, company_id, title, body, target_type, target_ids, importance, read_required, published_at, created_by) VALUES
 (1, 1, '【重要】7月キャンペーン施策について', '7月度は光回線+でんきセットのキャンペーンが開始されます。訴求ポイント資料を必ず確認の上、稼働してください。', 'all', '', 'important', 1, '2026-07-04 10:00:00', 2),
 (2, 1, '猛暑対策のお願い', '連日猛暑が続いています。移動時の水分補給・体調管理をお願いします。体調不良時は無理せず早めに連絡してください。', 'all', '', 'normal', 0, '2026-07-02 09:00:00', 2),
 (3, 1, '幕張催事：週末ブースレイアウト変更', '今週末より催事ブースのレイアウトが変更になります。設営手順書を添付しますので確認してください。', 'project', '3', 'important', 1, '2026-07-05 18:00:00', 2),
 (4, 1, '交通費申請の締切について', '今月分の交通費申請は月末最終稼働日までに日報備考欄へ記載をお願いします。', 'all', '', 'normal', 0, '2026-06-30 12:00:00', 3);

