INSERT OR IGNORE INTO follow_logs (follow_id, company_id, staff_id, manager_id, follow_type, content, next_action, status, related_project_id, created_at) VALUES
 (1, 1, 4, 2, 'interview', '日報未提出が続いている件で面談。業務量とモチベーション低下を確認。シフト調整を検討。', '1週間後に再面談。シフトを週3に調整して様子を見る。', 'open', 1, '2026-07-03 15:00:00'),
 (2, 1, 9, 2, 'phone', '入店報告の遅れについて電話確認。前日夜の準備を促した。', '今週の入店報告を毎日チェック。', 'open', 2, '2026-07-04 20:00:00'),
 (3, 1, 1, 2, 'praise', 'PI実績が2ヶ月連続で目標超過。称賛の連絡。', NULL, 'done', 1, '2026-07-01 11:00:00'),
 (4, 1, 16, 2, 'health', '欠勤が続いたため体調確認の連絡。回復傾向とのこと。', '次回稼働日に対面で様子確認。', 'open', 4, '2026-07-05 10:00:00'),
 (5, 1, 13, 2, 'claim', '申込書記入漏れインシデントについてヒアリング。チェックリスト運用を指導。', 'チェックリスト運用1週間後に確認。', 'open', 3, '2026-07-05 16:00:00');

INSERT OR IGNORE INTO consultations (consultation_id, company_id, staff_id, category, body, urgency, target_project_id, target_date, manager_reply, status, created_at) VALUES
 (1, 1, 16, 'health', '先週から体調が優れず、今週のシフトについて相談させてください。', 'high', 4, '2026-07-07', '無理しないでください。明日のシフトは代打を手配します。回復したら連絡ください。', 'in_progress', '2026-07-05 09:30:00'),
